<?= $this->extend('layouts/panel') ?>
<?= $this->section('content') ?>
<div class="page-actions"><p class="page-lead">Teklifleri, siparişleri ve onay durumlarını tek yerde izleyin.</p><?php if($canCreate): ?><div class="action-group"><a class="button button--secondary" href="<?= site_url('panel/siparisler/yeni?tur=quote') ?>">Yeni teklif</a><a class="button" href="<?= site_url('panel/siparisler/yeni?tur=order') ?>">Yeni sipariş</a></div><?php endif; ?></div>
<?php $statusClass = static fn(string $status): string => match ($status) { 'approved', 'delivered' => 'badge--success', 'procurement_waiting', 'reserved', 'partially_shipped', 'shipped', 'pending_approval' => 'badge--warning', 'cancelled' => 'badge--danger', default => 'badge--neutral', }; ?>
<section class="panel-card"><form class="filter-bar sales-filter" method="get"><label class="search-field"><span class="sr-only">Ara</span><input name="q" value="<?= esc($q) ?>" placeholder="Belge numarası veya müşteri ara"></label><label><span class="sr-only">Durum</span><select name="durum"><option value="">Bütün durumlar</option><?php foreach($statuses as $key=>$label): ?><option value="<?= esc($key) ?>" <?= $status===$key?'selected':'' ?>><?= esc($label) ?></option><?php endforeach; ?></select></label><label><span class="sr-only">Personel</span><select name="personel"><option value="">Bütün personel</option><?php foreach($employees as $person): ?><option value="<?= esc($person['id']) ?>" <?= (int)$employee===(int)$person['id']?'selected':'' ?>><?= esc($person['full_name']) ?></option><?php endforeach; ?></select></label><input type="date" name="baslangic" value="<?= esc($from) ?>" aria-label="Başlangıç tarihi"><input type="date" name="bitis" value="<?= esc($until) ?>" aria-label="Bitiş tarihi"><button class="button" type="submit">Süz</button></form><div class="table-wrap"><table class="data-table"><thead><tr><th>Belge</th><th>Müşteri</th><th>Satış personeli</th><th>Durum</th><th>Vergi hariç</th><th>Genel toplam</th><th>Tarih</th><th></th></tr></thead><tbody><?php foreach($documents as $doc): ?><tr><td data-label="Belge"><strong><?= esc($doc['document_number']) ?></strong><span class="cell-note"><?= esc($types[$doc['document_type']]??$doc['document_type']) ?></span></td><td data-label="Müşteri"><?= esc($doc['company_name']) ?></td><td data-label="Satış personeli"><?= esc($doc['sales_employee_name']??'Atanmamış') ?></td><td data-label="Durum"><span class="badge <?= $statusClass((string) $doc['status']) ?>"><?= esc($statuses[$doc['status']]??$doc['status']) ?></span></td><td data-label="Vergi hariç"><?= number_format((float)$doc['subtotal']-(float)$doc['discount_total'],2,',','.') ?> ₺</td><td data-label="Genel toplam"><strong><?= number_format((float)$doc['grand_total'],2,',','.') ?> ₺</strong></td><td data-label="Tarih"><?= esc(date('d.m.Y H:i',strtotime($doc['created_at']))) ?></td><td class="row-actions" data-label="İşlem"><a class="button button--secondary" href="<?= site_url('panel/siparisler/'.$doc['id']) ?>">Aç</a></td></tr><?php endforeach; ?></tbody></table><?php if(!$documents): ?><div class="empty-state"><h2>Belge bulunamadı</h2><p>Arama ölçütlerini değiştirin veya yeni bir teklif oluşturun.</p></div><?php endif; ?></div></section>
<?= $this->endSection() ?>
